class Solution {
public:
    string smallestNumber(string pattern) {
        string res = "";
        int n = pattern.size();
        vector<bool> used(10, false);
        for (int i = 1; i <= 9; ++i) {
            res += to_string(i);
            used[i] = true;
            if (i == 9) break;
            if (pattern[i - 1] == 'I') continue;
            int j = i + 1;
            while (j <= 9 && (j < i || pattern[j - 1] == 'D')) {
                if (!used[j]) {
                    res += to_string(j);
                    used[j] = true;
                }
                ++j;
            }
            --j;
            if (j > i) {
                string tmp = res.substr(i, j - i);
                reverse(tmp.begin(), tmp.end());
                res.replace(i, j - i, tmp);
            }
        }
        return res.substr(0, n + 1);
    }
};
```
